  "inlineSchema": "// Schéma de base de données ScaleVid.\n// SQLite par défaut (zéro config en local) — passe à \"postgresql\" pour la prod\n// (voir DATABASE_URL dans .env).\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  name         String\n  email        String   @unique\n  passwordHash String\n  plan         String   @default(\"creator\") // \"creator\" | \"agency\"\n  period       String   @default(\"monthly\") // \"monthly\" | \"annual\"\n  accountSlots Int      @default(1) // nombre de comptes payés dans l'abonnement\n  createdAt    DateTime @default(now())\n\n  socialAccounts SocialAccount[]\n  videos         Video[]\n}\n\n// Un compte YouTube ou TikTok connecté par l'utilisateur.\nmodel SocialAccount {\n  id             String    @id @default(uuid())\n  userId         String\n  user           User      @relation(fields: [userId], references: [id])\n  provider       String // \"youtube\" | \"tiktok\"\n  externalId     String // identifiant du compte chez la plateforme\n  handle         String // nom affiché (@handle)\n  accessToken    String // chiffré (voir tokenCrypto.js) avant stockage\n  refreshToken   String? // chiffré\n  tokenExpiresAt DateTime?\n  createdAt      DateTime  @default(now())\n\n  scheduledPosts ScheduledPost[]\n\n  @@unique([provider, externalId])\n}\n\n// Une vidéo source importée par l'utilisateur.\nmodel Video {\n  id          String   @id @default(uuid())\n  userId      String\n  user        User     @relation(fields: [userId], references: [id])\n  sourcePath  String // chemin/clé de stockage du fichier original\n  durationSec Float?\n  status      String   @default(\"uploaded\") // uploaded -> transcribing -> analyzing -> cutting -> done -> failed\n  error       String?\n  createdAt   DateTime @default(now())\n\n  clips Clip[]\n}\n\n// Un clip généré par le pipeline IA à partir d'une vidéo source.\nmodel Clip {\n  id         String   @id @default(uuid())\n  videoId    String?\n  video      Video?   @relation(fields: [videoId], references: [id])\n  startSec   Float\n  endSec     Float\n  title      String\n  caption    String\n  viralScore Int\n  reasoning  String?\n  outputPath String? // chemin du fichier découpé une fois prêt\n  status     String   @default(\"pending\") // pending -> rendering -> ready -> failed\n  createdAt  DateTime @default(now())\n\n  scheduledPosts ScheduledPost[]\n}\n\n// Une publication programmée d'un clip vers un compte connecté.\nmodel ScheduledPost {\n  id              String        @id @default(uuid())\n  clipId          String\n  clip            Clip          @relation(fields: [clipId], references: [id])\n  socialAccountId String\n  socialAccount   SocialAccount @relation(fields: [socialAccountId], references: [id])\n  scheduledAt     DateTime\n  status          String        @default(\"scheduled\") // scheduled -> publishing -> published -> failed\n  platformPostId  String?\n  error           String?\n  createdAt       DateTime      @default(now())\n}\n",
